import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { FiSearch, FiBell, FiMessageCircle } from 'react-icons/fi';
import { useAuth } from '../../contexts/AuthContext';
import './Header.css';

export default function Header() {
  const { user } = useAuth();
  const navigate = useNavigate();

  return (
    <header className="header">
      <div className="header__inner container">
        {/* Logo */}
        <Link to={user ? '/fil' : '/'} className="header__logo">
          <span className="header__logo-text">Sois<span>Relax</span></span>
        </Link>

        {/* Actions */}
        <div className="header__actions">
          <button
            className="header__icon-btn"
            onClick={() => navigate('/recherche')}
            aria-label="Rechercher"
          >
            <FiSearch size={22} />
          </button>

          {user && (
            <>
              <button
                className="header__icon-btn"
                onClick={() => navigate('/messages')}
                aria-label="Messages"
              >
                <FiMessageCircle size={22} />
              </button>
              <Link to={`/@${user.username}`}>
                {user.avatar_url ? (
                  <img
                    src={user.avatar_url}
                    alt={user.display_name}
                    className="avatar avatar--sm header__avatar"
                  />
                ) : (
                  <div className="header__avatar-placeholder avatar avatar--sm">
                    {user.display_name?.[0]?.toUpperCase()}
                  </div>
                )}
              </Link>
            </>
          )}

          {!user && (
            <Link to="/connexion" className="btn btn--primary btn--sm">
              Connexion
            </Link>
          )}
        </div>
      </div>
    </header>
  );
}
